import React from 'react';
import { Provider } from 'mobx-react';
import Routes, { IRouteItem } from '../config/routes.config';
import { message } from 'antd';
import ErrorBoundary from '@/components/ErrorBoundary';
import store from '@/store';
import dd from 'dingtalk-jsapi';
import { getLocal, setLocal } from '@/utils/method';
import { LOCAL_STORAGE } from '@/utils/constant';

/**
 * 改写整个应用render到dom树里。
 * 可能场景：
 *  1. 在渲染应用之前做权限校验，不通过则跳转到登录页（单点登录场景会很有用）
 *  2. 和pathRoutes配合，在render时请求后端接口，拿到动态路由
 * @param oldRender
 */
export async function render(oldRender: Function) {
    window.onerror = (errorMessage, scriptURI, lineNo, columnNo, error) => {
        const err = {
            异常信息: errorMessage,
            异常文件路径: scriptURI,
            异常行号: lineNo,
            异常列号: columnNo,
            异常堆栈信息: error
        };
        console.log(`------ 异常 ------`, err);
    };

    // 钉钉ID
    // 15772692400214720 Anton 测试
    // 01290319604408 超级管理 测试
    // setLocal(LOCAL_STORAGE.DING_ID, '01290319604408');
    // await store.userStore.login('01290319604408');
    // oldRender();

    const { userStore } = store;
    userStore.initLoginInfo();
    oldRender();
    return;
    if (userStore.ifLogin) {
        oldRender();
    } else {
        const loginHandler = async (dingUserId?: string) => {
            const result = await userStore.login(dingUserId);
            result.ifSuccess && oldRender();
        };
        if (getLocal(LOCAL_STORAGE.DING_ID)) {
            loginHandler();
        } else {
            if (dd.env.platform !== 'notInDingTalk') {
                // 当前是钉钉环境
                await userStore.getDingConfig();
                userStore
                    .getDingUserInfo()
                    .then((dingUserId: string) => {
                        loginHandler(dingUserId);
                    })
                    .catch(e => {
                        console.log(e);
                    });
            } else {
                message.error('请在钉钉中使用！');
                // setLocal(LOCAL_STORAGE.DING_ID, '01290319604408');
                // loginHandler('01290319604408');
            }
        }
    }
}

/**
 * 修改交给 react-dom 渲染时的根组件。
 * 比如用于在外面包一个 Provider，
 * @param container
 */
export function rootContainer(container: React.ReactNode) {
    // 包装 mobx 的 Provider
    // const providerDom = <Provider {...store}>{container}</Provider>;
    const providerDom = (
        <ErrorBoundary>
            <Provider {...store}>{container}</Provider>
        </ErrorBoundary>
    );
    return providerDom;
}
/**
 * 路由变化处理
 * @param {*} { location, routes, action }
 */
export function onRouteChange({ location }: { location: Record<string, string> }) {
    const { setMenu, setTitle, closeLoading } = store.uiStore;
    closeLoading(); // 路由切换，将loading状态关闭
    // 设置菜单选中项和header标题
    if (location.pathname === '/') {
        // 如果是根路由，直接设置菜单选中1
        setMenu(Routes[0].routes[0].key);
        setTitle(Routes[0].routes[0].title);
        return;
    }
    const regStr = new RegExp('\\' + location.pathname + '(\\/|$)');
    const result: IRouteItem[] = Routes[0].routes.filter(item => {
        // 查找path匹配的路由配置，且排除根路由
        return item.path !== '/' && regStr.test(item.path);
    });
    if (result.length === 0) {
        // 无效路由设置
        setMenu('0');
        setTitle('未找到页面');
    } else {
        // 有效路由设置
        result[0].key && setMenu(result[0].key);
        setTitle(result[0].title || '');
    }
}
