import { action, observable, runInAction } from 'mobx';
import { IResponse, get } from '@/utils/request';
import BaseListClass from '../BaseListClass';
import { enum_factory_type, enum_channel_type } from './typing';

const { ANALYSIS_SERVER } = APP_CONFIG;

/**
 * 获取站点列表
 * @param {Object} params 地区层级level
 * @return void
 */
const getFactoryList = async (params?: {
    f_province_id?: number; // 省id
    f_city_id?: number; // 市id
    f_district_id?: number; // 县区id
    f_work_start_time?: string; // 开业时间
    operationType?: enum_factory_type; // 门店类型，默认全部
    businessCategory?: enum_channel_type; // 渠道，默认全部
}): Promise<IResponse> => {
    try {
        const result = await get(`${ANALYSIS_SERVER}factory/querySimpleFactory`, {
            ...params,
            factoryStatus: '0',
            pageSize: 2000
        });
        return result;
    } catch (e) {
        return e;
    }
};

export class FactoryStore extends BaseListClass {}

const factoryStore = new FactoryStore(getFactoryList);
export default factoryStore;
