import { action, observable, runInAction } from 'mobx';
import { IResponse, get, post } from '@/utils/request';
import { enum_target_type, ITargetParams, ITargetSettingParams } from './typing';

const { ANALYSIS_SERVER } = APP_CONFIG;

export class TargetSettingStore {
    @observable
    selectedTargetType: enum_target_type = enum_target_type.profit; // 当前选中的
    @observable
    targetData: number | string = '--'; // 当前的目标值

    @action
    changeTargetType = (newType: enum_target_type) => {
        this.selectedTargetType = newType;
    };

    /**
     * 获取大区列表
     * @return void
     */
    getFactoryRegionList = async (): Promise<IResponse> => {
        try {
            const result = await get(`${ANALYSIS_SERVER}factory/list`);
            return result;
        } catch (e) {
            return e;
        }
    };

    /**
     * 获取目标值列表 更改store
     * @param {ITargetParams} params
     * @return void
     */
    @action
    getTargetList = async (params?: ITargetParams): Promise<IResponse> => {
        try {
            const result = await get(`${ANALYSIS_SERVER}target/list`, params);
            params?.f_month &&
                runInAction(() => {
                    const { ifSuccess, data } = result;
                    this.targetData = ifSuccess && data[0] ? Object.values(data[0])[0] : '--';
                });
            return result;
        } catch (e) {
            return e;
        }
    };

    /**
     * 获取目标值列表 不更改store
     * @param {ITargetParams} params
     * @return void
     */
    @action
    getTargetData = async (params?: ITargetParams): Promise<IResponse> => {
        try {
            const result = await get(`${ANALYSIS_SERVER}target/list`, params);
            return result;
        } catch (e) {
            return e;
        }
    };

    /**
     * 设置目标值
     * @param {ITargetSettingParams} params
     * @return void
     */
    setTargetList = async (params?: ITargetSettingParams): Promise<IResponse> => {
        try {
            const result = await get(`${ANALYSIS_SERVER}target/add`, params);
            return result;
        } catch (e) {
            return e;
        }
    };
}

const targetSettingStore = new TargetSettingStore();
export default targetSettingStore;
