import { observable, action, runInAction } from 'mobx';
import { IResponse, loadingResult, errResult } from '@/utils/request';

export const PAGE_SIZE = 10; // 默认，每页显示几条数据

/**
 * 通用的list的类
 * 没有特殊情况，直接new BaseListClass(requestMethod)即可
 * 有特殊的情况，可以继承此类
 */
class BaseListClass {
    protected requestMethod: Function;

    constructor(requestMethod) {
        if (typeof requestMethod !== 'function') {
            throw 'requestMethod 不能为空';
        }
        this.requestMethod = requestMethod;
    }

    @observable
    ifBaseListLoading = false; // 是否正在加载
    @observable
    hasMore = true; // 是否还有下一页
    @observable
    baseList: any[] = []; // 列表
    @observable
    pageNum = 1; // 页码
    @observable
    pageSize: number = PAGE_SIZE; // 每页几条数据
    @observable
    listName = '列表名字'; // 报错的时候能知道是哪个列表

    /**
     * 重置
     */
    reset() {
        runInAction(() => {
            this.ifBaseListLoading = false;
            this.hasMore = true;
            this.pageNum = 1;
            this.pageSize = PAGE_SIZE;
            this.baseList = [];
        });
    }

    /**
     * 主要调用逻辑
     * @param pageNum 指定加载第几页，没有指定则默认当前store中的pageNum字段
     * @param otherParams
     */
    @action
    async loadList(pageNum: any, otherParams?: object): Promise<IResponse> {
        this.ifBaseListLoading = true;
        try {
            const result = await this.requestMethod({
                pageNum,
                pageSize: this.pageSize,
                ...otherParams
            });
            runInAction(() => {
                this.ifBaseListLoading = false;
                const list = result.data || [];
                // 如果返回的length小于pageSize，肯定没有下一页了。
                if (list.length < this.pageSize || !result.success) {
                    this.hasMore = false;
                }
                if (pageNum > 1) {
                    // 页码大于1，用concat
                    this.baseList = this.baseList.concat(list);
                } else {
                    // 页码等于1，直接赋值
                    this.baseList = list;
                }
            });
            return result;
        } catch (e) {
            e = e || {};
            runInAction(() => {
                this.ifBaseListLoading = false;
                this.baseList = [];
            });
            return errResult;
        }
    }

    /**
     * 加载第2、3、4....页
     * @param params
     */
    loadMore(params: object = {}) {
        if (this.ifBaseListLoading) {
            return loadingResult;
        }
        if (!this.hasMore) {
            return {
                status: 111,
                code: 111,
                info: '没有更多',
                ifSuccess: false
            };
        }
        this.pageNum += 1;
        return this.loadList(this.pageNum, params);
    }

    /**
     * 加载第1页
     * @param params
     */
    initLoad(params: object = {}) {
        if (this.ifBaseListLoading) {
            return loadingResult;
        }
        this.pageNum = 1;
        this.hasMore = true;
        return this.loadList(this.pageNum, params);
    }

    getList(): any[] {
        return this.baseList;
    }

    /**
     * 设置名字，报错时使用。
     * @param listName
     */
    setListName(listName: string): void {
        this.listName = listName;
    }
}

export default BaseListClass;
