// 选中的省市信息 数据结构
export interface ISelectedProvince {
    f_province_id?: number; // 省份id
    f_city_id?: number; // 城市id
    f_district_id?: number; // 区县id
    group_province?: number; // 传值1 即为按省份组
    group_city?: number; // 传值1即为按城市分组，且group_province值不能为空
    group_district?: number; // 传值1即为按区县分组，且group_province、group_city值不能为空
}

// 需要统计的站点
export enum enum_analysis_factory_type {
    all = 0, // 全部
    self = 1, // 自营
    other = 2 // 非自营
}

// 通用的环比接口参数
export interface IAnalysisParams extends ISelectedProvince {
    startTime: string; // 开始时间
    endTime: string; // 结束时间
    type?: number; // 查询类型：0-全部（配合省市区），1-日，2-周，3-月
    orderType?: string; // 洗车类型：默认全部，精洗：XN000202 普洗：XN000201 快洗：XN000200 不分组:0
    f_factory_id?: number; // 站点id
    f_skill_score?: enum_analysis_factory_type; // 需要统计营收的站点
    dingUserId?: string; // 钉钉用户id
}
