import { action, observable, runInAction } from 'mobx';
import { IResponse, get, post } from '@/utils/request';
import { IWordItem } from './typing';

export class HomeStore {

    /**
     * 获取关键词列表
     * @param {} params
     * @return void
     */
    @action
    getWordList = async (params): Promise<IResponse> => {
        params = {
            param: JSON.stringify({
                industryId: ''
            })
        };
        try {
            const result = await get(`https://thor.weidian.com/mclaren/shopSearchKeyword.hotList/2.0`, params);
            runInAction(() => {
                const { ifSuccess, data } = result;
            });
            return result;
        } catch (e) {
            return e;
        }
    };
}

const homeStore = new HomeStore();
export default homeStore;
