import { action, observable, runInAction } from 'mobx';
import { IResponse, get } from '@/utils/request';
import { enum_region_level } from './typing';

const { ANALYSIS_SERVER } = APP_CONFIG;

export class CommonStore {
    /**
     * 获取地区列表
     * @param {number} f_region_level 地区层级level
     * @param {number} f_parent_id 父级id
     * @return void
     */
    @action
    getRegionList = async (f_region_level: enum_region_level, f_parent_id: number): Promise<IResponse> => {
        try {
            const result = await get(`${ANALYSIS_SERVER}region/findRegion`, {
                f_region_level,
                f_parent_id
            });
            return result;
        } catch (e) {
            return e;
        }
    };
}

const commonStore = new CommonStore();
export default commonStore;
