import moment from 'moment';
import { enum_file_type, FILE_TYPE_CONFIG } from './constant';
/**
 * 传入date，计算是星期几
 * @param {Date|string} date 需要计算的日期
 * @return {string} 计算结果
 */
export const getWeekDayName = (date: Date | string): string => {
    const weekNameList = ['日', '一', '二', '三', '四', '五', '六'];
    const week = new Date(date).getDay();
    return weekNameList[week];
};

/**
 * 计算目标日期 当月有几天
 * @param {Date|string} date 需要计算的日期
 * @return {string} 计算结果
 */
export const getMonthDays = (date: Date) => {
    /* 获取当前月份 */
    const curMonth = date.getMonth();
    /*  生成实际的月份: 由于curMonth会比实际月份小1, 故需加1 */
    date.setMonth(curMonth + 1);
    /* 将日期设置为0, 这里为什么要这样设置, 我不知道原因, 这是从网上学来的 */
    date.setDate(0);
    /* 返回当月的天数 */
    return date.getDate();
};

/**
 * 传入日期，格式，按格式换算日期
 * @param {Date|string} date 需要格式化的日期
 * @param {string} format 格式化的格式指定 YYYY-MM-DD HH:MIMI:SS
 * @return {string} 格式化结果
 */
export const formatDate = (date: Date | string, format: string) => {
    const newDate: Date = moment.utc(date).toDate();
    const year = newDate.getFullYear();
    const month = newDate.getMonth() + 1;
    const day = newDate.getDate();
    const hour_24 = newDate.getHours(); // 24进制小时
    const minute = newDate.getMinutes();
    const second = newDate.getSeconds();

    // 格式化年份
    format = format.replace(/YYYY/i, year.toString());
    // 格式化月份
    const monthStr = month < 10 ? '0' + month : month.toString();
    format = format.replace(/MM/i, monthStr);
    // 格式化日期
    const dayStr = day < 10 ? '0' + day : day.toString();
    format = format.replace(/DD/i, dayStr);
    // 格式化24进制小时
    const hour_24_Str = hour_24 < 10 ? '0' + hour_24 : hour_24.toString();
    format = format.replace(/HH/, hour_24_Str);
    // 格式化12进制小时
    const hour_12 = hour_24 > 12 ? hour_24 - 12 : hour_24;
    const hour_12_str = hour_12 < 10 ? '0' + hour_12 : hour_12.toString();
    format = format.replace(/hh/, hour_12_str);
    // 格式化分钟
    const minuteStr = minute < 10 ? '0' + minute : minute.toString();
    format = format.replace(/MIMI/i, minuteStr);
    // 格式化秒
    const secondStr = second < 10 ? '0' + second : second.toString();
    format = format.replace(/SS/i, secondStr);
    return format;
};

export const formatPreDay = (date: Date | string, days: number) => {
    if (!days) {
        days = 1;
    }
    const tmpDate = new Date(date);
    const tmpDate1 = new Date(tmpDate.getTime() - days * 24 * 1000 * 60 * 60);
    const format = formatDate(tmpDate1, 'YYYY-MM-DD');
    return format;
};

/**
 * 防抖函数
 * @param {Function} handler 需要格式化的日期
 * @param {number} time 格式化的格式指定 YYYY-MM-DD HH:MIMI:SS
 * @param {?Function} preFunc 格式化结果
 * @return {Function} 返回防抖包装后的handler
 */
export const debounce = (handler: Function, time: number, preFunc?: Function): Function => {
    let timer: NodeJS.Timeout | null = null;
    return params => {
        preFunc && preFunc();
        timer !== null && clearTimeout(timer);
        timer = setTimeout(() => handler(params), time);
        // window.requestAnimationFrame(() => handler(params));
    };
};

/**
 * 获取cookie
 * @param {string} key 要获取的cookie key
 * @return {string} cookie内容
 */
export const getCookie = (key: string): string => {
    const name = key + '=';
    const ca = document.cookie.split(';');
    for (let i = 0; i < ca.length; i++) {
        const c = ca[i].trim();
        if (c.indexOf(name) === 0) {
            return c.substring(name.length, c.length);
        }
    }
    return '';
};

/**
 * 设置cookie
 * @param {string} key 要设置的cookie key
 * @param {string | number} value 值
 * @param {number?} expiresDay 过期天数
 * @return {void}
 */
export const setCookie = (key: string, value: string | number, expiresDay?: number): void => {
    let cookieStr = key + '=' + value + '; ';
    if (expiresDay) {
        const date = new Date();
        date.setTime(date.getTime() + expiresDay * 24 * 60 * 60 * 1000);
        cookieStr += 'expires=' + date.toUTCString();
    }
    document.cookie = cookieStr;
};

/**
 * 清除某个cookie
 * @param {string} key 要清除的cookie key
 * @return {void}
 */
export const clearCookie = (key: string) => {
    setCookie(key, '');
};

/**
 * 获取localStorage
 * @param {string} key 要获取的storage key
 * @return {string} storage值
 */
export const getLocal = (key: string): string => {
    return window.localStorage.getItem(key) || '';
};

/**
 * 设置localStorage
 * @param {string} key 要设置的storage key
 * @param {string | number} value 值
 * @return {void}
 */
export const setLocal = (key: string, value: string | number) => {
    window.localStorage.setItem(key, value.toString());
};

/**
 * 清空某个localStorage
 * @param {string} key 要清空的storage key
 * @return {void}
 */
export const clearLocal = (key: string) => {
    window.localStorage.setItem(key, '');
};

/**
 * 下载某个文件
 * @param file {any} 文件流
 * @param name string 下载的文件名称 记得带上后缀名
 */
export const downloadFile = (params: { file: any; name: string; type: enum_file_type }) => {
    const { file, name, type } = params;
    let blob = file;
    if (!(blob instanceof Blob)) {
        blob = new Blob([blob], { type: FILE_TYPE_CONFIG[type].type });
    }
    const link = document.createElement('a');
    // 设置导出的文件名
    link.download = `${name}${FILE_TYPE_CONFIG[type].suffix}`;
    link.href = URL.createObjectURL(blob);
    // 点击获取文件
    link.click();
};

/**
 * 删除Object的空属性
 * @param {Object} obj 原对象
 * @return {Object} 去空后的新对象
 */
export const removeEmpty = (obj: any): any => {
    const newObj: any = {};
    for (const key in obj) {
        const item = obj[key];
        // 是否需要去掉空数组 空对象 这个有歧义所以就不加了，有需要可另外声明一个方法
        if (item === '' || item === null || item === undefined) continue;
        newObj[key] = item;
    }
    return newObj;
};

/**
 * 计算真实渲染的像素，因为设计稿宽度是 1600px，根据窗口尺寸再按比例调整
 * @param {number} size 设计稿的像素
 * @return {number}
 */
export const getSize = (size: number): number => (document.body.clientWidth * size) / 1600;

/**
 * 计算要显示的刻度
 * @param {number} length 数据源长度，原坐标轴刻度个数
 * @param {number} maxTickCount 最大刻度个数
 * @param {number} activeTick 当前选中的刻度
 * @return {number[]} 返回计算得到的刻度
 */
export const getTicks = ({
    length,
    maxTickCount = Math.ceil(getSize(40)),
    activeTick
}: {
    length: number;
    maxTickCount?: number;
    activeTick?: number;
}): number[] => {
    // interval 表示两个刻度之间相差几个刻度 至少2，即至少间隔1个
    const newTicks: number[] = [];
    if (length > maxTickCount) {
        const interval = Math.max(2, Math.ceil(length / maxTickCount));
        for (let i = 0; i < maxTickCount; i++) {
            const newTick = Math.round(i * interval);
            newTicks.push(Math.min(newTick, length - 1));
        }
        if (activeTick && activeTick > -1 && newTicks.findIndex(item => item === activeTick) === -1) {
            newTicks.push(activeTick);
        }
    } else {
        for (let i = 0; i < length; i++) {
            newTicks.push(i);
        }
    }
    return newTicks;
};

/**
 * 计算图表y轴的最大最小值
 * @param {any[]} data 数据源
 * @param {string} key 进行比较的key字段，没有就以data的item作为比较对象
 * @return {number}
 */
export const getRange = (
    data: any[],
    key?: string
): {
    max: any;
    min?: any;
    maxY?: any;
    minY?: any;
} => {
    let max, min;
    data.forEach(item => {
        const currentData = key ? item[key] : item;
        if (!isNaN(currentData)) {
            max = typeof max !== 'undefined' ? Math.max(currentData, max) : currentData;
            currentData !== max && (min = typeof min !== 'undefined' ? Math.min(currentData, min) : currentData);
        }
    });
    const distance = max - min;
    const maxY = max + distance * 0.2;
    const minY = min - distance * 0.3;
    return { max, min, maxY, minY };
};

/**
 * 判断当前是不是PC设备
 */
export const isPC = () => {
    const userAgentInfo = navigator.userAgent;
    const Agents = ['Android', 'iPhone', 'SymbianOS', 'Windows Phone', 'iPad', 'iPod'];
    let flag = true;
    for (let v = 0; v < Agents.length; v++) {
        if (userAgentInfo.indexOf(Agents[v]) > 0) {
            flag = false;
            break;
        }
    }
    return flag;
};
