import React from 'react';

interface IProps {
    children: React.ReactNode; // errorCatch包裹的内容
}
interface IState {
    hasError: boolean; // 是否有异常
}

class ErrorBoundary extends React.Component<IProps, IState> {
    constructor(props) {
        super(props);
        this.state = { hasError: false };
    }
    componentDidCatch(error, info) {
        // Display fallback UI
        this.setState({ hasError: true });
        // You can also log the error to an error reporting service
        console.log(error, info);
    }
    render() {
        if (this.state.hasError) {
            // You can render any custom fallback UI
            return <h1>Something went wrong.</h1>;
        }
        return this.props.children;
    }
}

/**
 * 导出用errBoundary包裹的高阶函数
 * @param {React.ComponentType<P>} Target errCatch 包裹的组件
 */
export const errBoundary = <P, S>(Target: React.ComponentClass<P, S>) => {
    class Wrap extends React.Component<P, S> {
        render() {
            return (
                <ErrorBoundary>
                    <Target {...(this.props as P)} />
                </ErrorBoundary>
            );
        }
    }
    return Wrap;
};

export default ErrorBoundary;
