import { action, observable, runInAction } from 'mobx';
import { IResponse, get } from '@/utils/request';

const { WEBSOCKET_SERVER, ANALYSIS_SERVER } = APP_CONFIG;

export class StatisticsStore {
    /**
     * 获取运营数据统计情况
     * @param {string} startTime 开始时间
     * @param {string} endTime 结束时间
     */
    @action
    getBusinessStatistics = async (startTime: string, endTime: string): Promise<IResponse> => {
        try {
            const SERVER_ID = 2002;
            const result = await get(`${WEBSOCKET_SERVER}washData/countWashMachinelogToday`, {
                serviceId: SERVER_ID,
                startTime,
                endTime
            });
            return result;
        } catch (e) {
            return e;
        }
    };

    /**
     * 站点数据
     */
    @action
    getFactoryData = async (): Promise<IResponse> => {
        try {
            const result = await get(`${ANALYSIS_SERVER}factory/bdFactory`);
            return result;
        } catch (e) {
            return e;
        }
    };

    /**
     * 维护站点数据
     */
    @action
    getMaintainData = async (): Promise<IResponse> => {
        try {
            const result = await get(`${ANALYSIS_SERVER}factory/maintainFactory`);
            return result;
        } catch (e) {
            return e;
        }
    };

    /**
     * 获取运营率环比
     * @param {string} startTime 开始时间
     * @param {string} endTime 结束时间
     */
    @action
    getOperationRateDOD = async (startTime: string, endTime: string): Promise<IResponse> => {
        try {
            const result = await get(`${ANALYSIS_SERVER}operatingRate/list`, {
                startTime,
                endTime
            });
            return result;
        } catch (e) {
            return e;
        }
    };
}

const statisticsStore = new StatisticsStore();
export default statisticsStore;
