import { TargetSettingStore } from './index';
export default TargetSettingStore;

// 目标值类型枚举
export enum enum_target_type {
    profit = 1, // 毛利
    positiveRate = 2, // 好评率
    shareRate = 3, // 转介绍率
    repurchaseRate = 4 // 复购率
}

export enum enum_month_name {
    'M01' = 'f_january',
    'M02' = 'f_february',
    'M03' = 'f_march',
    'M04' = 'f_april',
    'M05' = 'f_may',
    'M06' = 'f_june',
    'M07' = 'f_july',
    'M08' = 'f_august',
    'M09' = 'f_september',
    'M10' = 'f_octover',
    'M11' = 'f_noveber',
    'M12' = 'f_december'
}

// 目标值通用 参数
export interface ITargetCommonParams {
    f_province_id?: number; // 大区id
    f_year?: string; // 年
    f_type?: enum_target_type; // 目标类型
}

// 获取目标值 参数
export interface ITargetParams extends ITargetCommonParams {
    f_month?: enum_month_name; // 月
}

// 修改目标值 参数
export interface ITargetSettingParams extends ITargetCommonParams {
    f_id?: number; // 目标值id
    f_january?: string; // 1月目标值 以下同理
    f_february?: string;
    f_march?: string;
    f_april?: string;
    f_may?: string;
    f_june?: string;
    f_july?: string;
    f_august?: string;
    f_september?: string;
    f_octover?: string;
    f_noveber?: string;
    f_december?: string; // 12月目标值 以上同理
}

// 大区 数据结构
export interface IRegionItem {
    f_province_id: number; // 大区id
    f_province: string; // 大区名称
}

// 大区目标值 数据结构
export interface ITargetItem extends ITargetSettingParams {
    f_createUser?: string; // 修改人 "11111"
    f_createTime?: string; // 创建时间 "2020-05-14T10:23:28.000+0000"
    f_updateTime?: string; // 更新时间 "2020-05-14T10:23:28.000+0000"
}

// 大区目标值 初始值
export const initTargetItem: ITargetItem = {
    f_january: '',
    f_february: '',
    f_march: '',
    f_april: '',
    f_may: '',
    f_june: '',
    f_july: '',
    f_august: '',
    f_september: '',
    f_octover: '',
    f_noveber: '',
    f_december: ''
};
